targets.rawSql:
SELECT score
FROM dashboard.sentiment_${sentiment_interval}
WHERE score IS NOT NULL
ORDER BY create_time DESC
LIMIT 1;

SELECT confidence
FROM dashboard.sentiment_${sentiment_interval}
WHERE confidence IS NOT NULL
ORDER BY create_time DESC
LIMIT 1;

SELECT count AS reddit_mentions
FROM dashboard.sentiment_${sentiment_interval}
ORDER BY create_time DESC
LIMIT 1;

SELECT
  create_time AS time,
  score AS "Score"
FROM dashboard.sentiment_${sentiment_interval}
WHERE $__timeFilter(create_time)
ORDER BY create_time;

SELECT
  create_time AS time,
  confidence AS "Confidence"
FROM dashboard.sentiment_${sentiment_interval}
WHERE $__timeFilter(create_time)
ORDER BY create_time;

SELECT
  create_time AS time,
  count::DOUBLE PRECISION AS "Mentions"
FROM dashboard.sentiment_${sentiment_interval}
WHERE $__timeFilter(create_time)
ORDER BY create_time;
